using System.Text.Json;using Games.Horse.Application.Services;using Games.Horse.Domain.Results;using Games.Horse.Transport.Grpc.Wire;using Grpc.Core;
namespace Games.Horse.Transport.Grpc;
internal static class HorseWire{static readonly JsonSerializerOptions O=new(JsonSerializerDefaults.Web);public static ContractCall Call<T>(T x)=>new(){PayloadJson=JsonSerializer.Serialize(x,O)};public static ContractReply Reply<T>(T x)=>new(){PayloadJson=JsonSerializer.Serialize(x,O)};public static T Read<T>(this ContractCall x)=>JsonSerializer.Deserialize<T>(x.PayloadJson,O)!;public static T Read<T>(this ContractReply x)=>JsonSerializer.Deserialize<T>(x.PayloadJson,O)!;}
internal sealed record BetCall(long UserId,string Name,long ScopeId,int HorseId,int Amount,int SourceId);internal sealed record ScopeCall(long? ScopeId);internal sealed record RunCall(long UserId,HorseRunKind Kind,long ScopeId);internal sealed record FileCall(string RaceDate,long ScopeId,string FileId);internal sealed record EmptyReply;
public sealed class HorseGrpcEndpoint(IHorseService s):HorseApi.HorseApiBase
{public override async Task<ContractReply> PlaceBet(ContractCall r,ServerCallContext c){var x=r.Read<BetCall>();return HorseWire.Reply(await s.PlaceBetAsync(x.UserId,x.Name,x.ScopeId,x.HorseId,x.Amount,x.SourceId,c.CancellationToken));}public override async Task<ContractReply> GetInfo(ContractCall r,ServerCallContext c)=>HorseWire.Reply(await s.GetTodayInfoAsync(r.Read<ScopeCall>().ScopeId,c.CancellationToken));public override async Task<ContractReply> GetResult(ContractCall r,ServerCallContext c)=>HorseWire.Reply(await s.GetTodayResultAsync(r.Read<ScopeCall>().ScopeId??0,c.CancellationToken));public override async Task<ContractReply> RunRace(ContractCall r,ServerCallContext c){var x=r.Read<RunCall>();return HorseWire.Reply(await s.RunRaceAsync(x.UserId,x.Kind,x.ScopeId,c.CancellationToken));}public override async Task<ContractReply> SaveFile(ContractCall r,ServerCallContext c){var x=r.Read<FileCall>();await s.SaveFileIdAsync(x.RaceDate,x.ScopeId,x.FileId,c.CancellationToken);return HorseWire.Reply(new EmptyReply());}}
public sealed class GrpcHorseService(HorseApi.HorseApiClient c):IHorseService
{public Task<BetResult> PlaceBetAsync(long u,string n,long sc,int h,int a,CancellationToken ct)=>PlaceBetAsync(u,n,sc,h,a,0,ct);public async Task<BetResult> PlaceBetAsync(long u,string n,long sc,int h,int a,int src,CancellationToken ct)=>(await c.PlaceBetAsync(HorseWire.Call(new BetCall(u,n,sc,h,a,src)),cancellationToken:ct)).Read<BetResult>();public async Task<RaceInfo> GetTodayInfoAsync(long? sc,CancellationToken ct)=>(await c.GetInfoAsync(HorseWire.Call(new ScopeCall(sc)),cancellationToken:ct)).Read<RaceInfo>();public async Task<TodayRaceResult> GetTodayResultAsync(long sc,CancellationToken ct)=>(await c.GetResultAsync(HorseWire.Call(new ScopeCall(sc)),cancellationToken:ct)).Read<TodayRaceResult>();public async Task<RaceOutcome> RunRaceAsync(long u,HorseRunKind k,long sc,CancellationToken ct)=>(await c.RunRaceAsync(HorseWire.Call(new RunCall(u,k,sc)),cancellationToken:ct)).Read<RaceOutcome>();public async Task SaveFileIdAsync(string d,long sc,string f,CancellationToken ct)=>_ = await c.SaveFileAsync(HorseWire.Call(new FileCall(d,sc,f)),cancellationToken:ct);}
